import { describe, expect, it } from 'vitest';
import {
  THOTH_FOLD_PHASE_FRAME_KIND,
  THOTH_FOLD_THEOREM_REFS,
  THOTH_FOLD_WINDOW_LENGTH,
  auditThothFoldCoverage,
  encodeThothFoldPhaseFrame,
  isThothFoldPhaseFrame,
  nextThothFoldTick,
  renderThothFoldPhasePromptContext,
  thothAmputatedPhaseAt,
  thothFoldPhaseMetrics,
  thothFoldPhaseOathInput,
  thothPhaseAt,
} from '../src/thoth-fold-phase';
import type { ThothSelfTalkPhase } from '../src/thoth-fold-phase';

function schedule(
  scheduler: (tick: number) => ThothSelfTalkPhase,
  ticks: number,
): ThothSelfTalkPhase[] {
  return Array.from({ length: ticks }, (_, tick) => scheduler(tick));
}

describe('Thoth fold-phase oath', () => {
  it('the honored scheduler cycles listen -> speak -> reflect -> fold', () => {
    expect(schedule(thothPhaseAt, 8)).toEqual([
      'listen',
      'speak',
      'reflect',
      'fold',
      'listen',
      'speak',
      'reflect',
      'fold',
    ]);
    expect(thothPhaseAt(7)).toBe(thothPhaseAt(3));
  });

  it('fold ticks are cofinal: every anchor has a fold at or after it', () => {
    expect(nextThothFoldTick(0)).toBe(3);
    expect(nextThothFoldTick(3)).toBe(3);
    expect(nextThothFoldTick(4)).toBe(7);
    for (let anchor = 0; anchor < 32; anchor += 1) {
      const foldTick = nextThothFoldTick(anchor);
      expect(foldTick).toBeGreaterThanOrEqual(anchor);
      expect(thothPhaseAt(foldTick)).toBe('fold');
    }
  });

  it('the honored scheduler passes the window audit at any length', () => {
    for (const ticks of [4, 9, 17, 64]) {
      const audit = auditThothFoldCoverage(schedule(thothPhaseAt, ticks));
      expect(audit.honored).toBe(true);
      expect(audit.firstViolationAt).toBeUndefined();
      expect(audit.foldCount).toBe(Math.floor((ticks + 0) / 4));
    }
  });

  it('the amputated scheduler never folds and fails its first full window', () => {
    const history = schedule(thothAmputatedPhaseAt, 16);
    expect(history.every((phase) => phase === 'listen' || phase === 'speak')).toBe(
      true,
    );
    const audit = auditThothFoldCoverage(history);
    expect(audit.honored).toBe(false);
    expect(audit.foldCount).toBe(0);
    expect(audit.firstViolationAt).toBe(0);
  });

  it('produces a mast-bound oath citing the coverage theorem', () => {
    const oath = thothFoldPhaseOathInput('thoth-host');
    expect(oath.bindingStrength).toBe('mast-bound');
    expect(oath.scheduleMode).toBe('periodic');
    expect(oath.theoremRef).toBe(THOTH_FOLD_THEOREM_REFS.coverage);
    expect(oath.invariant).toContain(`${THOTH_FOLD_WINDOW_LENGTH}-tick`);
    expect(oath.consent).toContain('not amputatable');
  });

  it('encodes a non-authoritative audit frame for both verdicts', () => {
    const honored = thothFoldPhaseMetrics(
      auditThothFoldCoverage(schedule(thothPhaseAt, 12)),
    );
    expect(honored.theoremRef).toBe(THOTH_FOLD_THEOREM_REFS.coverage);
    const honoredFrame = encodeThothFoldPhaseFrame('thoth-host', honored);
    expect(isThothFoldPhaseFrame(honoredFrame)).toBe(true);
    expect(honoredFrame.mediaType.Abstract).toBe(THOTH_FOLD_PHASE_FRAME_KIND);
    expect(honoredFrame.deficit).toBe(0);
    expect(honoredFrame.attributes.oath_honored).toBe('true');
    expect(honoredFrame.attributes.first_violation_at).toBe('none');

    const amputated = thothFoldPhaseMetrics(
      auditThothFoldCoverage(schedule(thothAmputatedPhaseAt, 12)),
    );
    expect(amputated.theoremRef).toBe(THOTH_FOLD_THEOREM_REFS.amputation);
    const amputatedFrame = encodeThothFoldPhaseFrame('thoth-host', amputated);
    expect(amputatedFrame.deficit).toBe(1);
    expect(amputatedFrame.attributes.oath_honored).toBe('false');
    expect(amputatedFrame.attributes.fold_count).toBe('0');

    const context = renderThothFoldPhasePromptContext(amputated);
    expect(context).toContain('kind=thoth.fold-phase.v1');
    expect(context).toContain('honored=false');
    expect(context).toContain(THOTH_FOLD_THEOREM_REFS.amputation);
  });
});
